function Search({
  filters,
  onFiltersChange,
  onSearch,
  onReset,
  isSearching,
  activeFilterCount
}) {
  const updateField = (field, value) => {
    onFiltersChange((current) => ({
      ...current,
      [field]: value
    }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    await onSearch(filters);
  };

  return (
    <section className="panel">
      <h2>Smart Search</h2>
      <p className="panel-copy">
        Search across document names, metadata, file type, and upload date ranges.
      </p>

      <form onSubmit={handleSubmit} className="stack">
        <input
          type="text"
          className="text-input"
          placeholder="Keyword search across names, extensions, and metadata"
          value={filters.query}
          onChange={(event) => updateField("query", event.target.value)}
        />

        <input
          type="text"
          className="text-input"
          placeholder="Metadata search (content type, key, original filename)"
          value={filters.metadata}
          onChange={(event) => updateField("metadata", event.target.value)}
        />

        <div className="filter-grid">
          <select
            className="text-input"
            value={filters.fileType}
            onChange={(event) => updateField("fileType", event.target.value)}
          >
            <option value="">All types</option>
            <option value="pdf">PDF</option>
            <option value="text">TXT / text</option>
            <option value="word">Word</option>
            <option value="image">Image</option>
            <option value="json">JSON</option>
            <option value="csv">CSV</option>
          </select>

          <input
            type="datetime-local"
            className="text-input"
            value={filters.dateFrom}
            onChange={(event) => updateField("dateFrom", event.target.value)}
          />

          <input
            type="datetime-local"
            className="text-input"
            value={filters.dateTo}
            onChange={(event) => updateField("dateTo", event.target.value)}
          />
        </div>

        <div className="button-row">
          <button type="submit" className="primary-button search-button">
            {isSearching ? "Searching..." : "Run Smart Search"}
          </button>
          <button type="button" className="secondary-button" onClick={onReset}>
            Reset Filters
          </button>
          <span className="search-chip">{activeFilterCount} active filter(s)</span>
        </div>
      </form>
    </section>
  );
}

export default Search;
